reply = reply.replace(new RegExp("[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}", "gi"), "contrato");
reply = reply.replace(new RegExp("__SAFE_URL_([0-9]+)__", "g"), (_, index) => protectedUrls[Number(index)] || "");
